import{_ as e,o as i,c as r,S as t}from"./chunks/framework.DZlzLDBr.js";const p=JSON.parse('{"title":"Sprout Wiki","description":"","frontmatter":{},"headers":[],"relativePath":"Home.md","filePath":"Home.md","lastUpdated":null}'),s={name:"Home.md"};function l(o,a,n,d,h,c){return i(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="sprout-wiki" tabindex="-1">Sprout Wiki <a class="header-anchor" href="#sprout-wiki" aria-label="Permalink to &quot;Sprout Wiki&quot;">​</a></h1><p>Last modified: 13/02/2026</p><h2 id="what-is-sprout" tabindex="-1">What is Sprout? <a class="header-anchor" href="#what-is-sprout" aria-label="Permalink to &quot;What is Sprout?&quot;">​</a></h2><p>Sprout is an Obsidian plugin for making flashcards in your notes and reviewing them with spaced repetition (a system that shows cards again at the right time).</p><p>With Sprout, you can:</p><ul><li>Create flashcards directly in Markdown notes</li><li>Review cards in study sessions</li><li>Track progress in analytics</li><li>Browse and edit cards in one place</li></ul><h2 id="start-here" tabindex="-1">Start here <a class="header-anchor" href="#start-here" aria-label="Permalink to &quot;Start here&quot;">​</a></h2><ol><li><a href="./Installation">Installation</a></li><li><a href="./Creating-Cards">Creating Cards</a></li><li><a href="./Study-Sessions">Study Sessions</a></li></ol><h2 id="card-types" tabindex="-1">Card types <a class="header-anchor" href="#card-types" aria-label="Permalink to &quot;Card types&quot;">​</a></h2><ul><li><a href="./Basic-&amp;-Reversed-Cards">Basic &amp; Reversed Cards</a></li><li><a href="./Cloze-Cards">Cloze Cards</a></li><li><a href="./Image-Occlusion">Image Occlusion</a></li><li><a href="./Multiple-Choice-Questions">Multiple Choice Questions</a></li><li><a href="./Ordered-Questions">Ordered Questions</a></li></ul><p>See <a href="./Cards">Cards</a> for the full overview.</p><h2 id="study-basics" tabindex="-1">Study basics <a class="header-anchor" href="#study-basics" aria-label="Permalink to &quot;Study basics&quot;">​</a></h2><ul><li>Reviews are scheduled automatically using FSRS.</li><li>You can study by vault, folder, note, or group.</li><li>Daily new and review limits are applied per study scope and reset each day.</li><li>Practice mode does not change scheduling.</li></ul><p>See <a href="./Study-Sessions">Study Sessions</a>, <a href="./Scheduling">Scheduling</a>, and <a href="./Grading">Grading</a>.</p><h2 id="other-tools" tabindex="-1">Other tools <a class="header-anchor" href="#other-tools" aria-label="Permalink to &quot;Other tools&quot;">​</a></h2><ul><li><a href="./Card-Browser">Card Browser</a> for search, filters, sorting, and bulk actions</li><li><a href="./Analytics">Analytics</a> and <a href="./Charts">Charts</a> for progress tracking</li><li><a href="./Text-to-Speech">Text to Speech</a> for spoken cards</li><li><a href="./Reading-View">Reading View</a> for reviewing extracted content</li><li><a href="./Flags">Flags</a> for inline circle-flag tokens in card text</li></ul><h2 id="important-notes" tabindex="-1">Important notes <a class="header-anchor" href="#important-notes" aria-label="Permalink to &quot;Important notes&quot;">​</a></h2><ul><li>If card syntax is invalid, the card is quarantined until fixed.</li><li>Some actions are permanent, including <strong>Delete all flashcards</strong> and reset actions.</li></ul><p>Before large imports or resets, create a backup (see <a href="./Backups">Backups</a>).</p><h2 id="need-help" tabindex="-1">Need help? <a class="header-anchor" href="#need-help" aria-label="Permalink to &quot;Need help?&quot;">​</a></h2><ul><li><a href="./Settings">Settings</a> for all options</li><li><a href="./Syncing">Syncing</a> for indexing and parse issues</li><li><a href="./Widget">Widget</a> for deck tree behaviour</li></ul>',21)])])}const f=e(s,[["render",l]]);export{p as __pageData,f as default};
